<?php $adminTitle='Kids Learner Progress';require_once __DIR__.'/../includes/kids-admin-header.php';$age=(string)($_GET['age']??'All');$sql='SELECT p.*,l.full_name,g.guardian_email,g.age_group,c.title course_title,kl.title lesson_title,a.title activity_title FROM learner_progress p JOIN learners l ON l.id=p.learner_id LEFT JOIN kids_guardian_profiles g ON g.learner_id=l.id JOIN kids_courses c ON c.id=p.course_id LEFT JOIN kids_lessons kl ON kl.id=p.lesson_id LEFT JOIN kids_activities a ON a.id=p.activity_id';$params=[];if(in_array($age,['6-8','9-12','13-15'],true)){$sql.=' WHERE g.age_group=?';$params[]=$age;}$sql.=' ORDER BY p.updated_at DESC';$s=$pdo->prepare($sql);$s->execute($params);$rows=$s->fetchAll();?>
<div class="admin-top"><div><p class="eyebrow">Kids Academy</p><h1>Learner Progress</h1></div><form><select class="form-select" name="age" onchange="this.form.submit()"><option>All</option><?php foreach(['6-8','9-12','13-15'] as $g):?><option <?=$age===$g?'selected':''?>><?=$g?></option><?php endforeach?></select></form></div><div class="glass-card table-responsive"><table class="table table-dark align-middle"><thead><tr><th>Learner</th><th>Age</th><th>Guardian</th><th>Course / Content</th><th>Score</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['age_group']??'—')?></td><td><?=e($r['guardian_email']??'Standard learner')?></td><td><strong><?=e($r['course_title'])?></strong><small class="d-block text-secondary"><?=e($r['activity_title']??$r['lesson_title']??'Course activity')?></small></td><td><?=isset($r['score'])?(int)$r['score'].'%':'—'?></td><td><?=e($r['status'])?></td></tr><?php endforeach?></tbody></table></div>
<?php require_once __DIR__.'/../includes/kids-admin-footer.php';?>
